--
-- テーブルの構造 `members`
--

CREATE TABLE `members` (
  `id` int(11) NOT NULL COMMENT '会員ID (主キー自動採番)',
  `member_id` int(11) NOT NULL COMMENT '会員ID (一意)',
  `member_name` varchar(100) NOT NULL COMMENT '会員名',
  `member_kana` varchar(100) NOT NULL COMMENT '会員カナ',
  `parent_name` varchar(100) DEFAULT NULL COMMENT '保護者名 (未成年の場合など)',
  `parent_kana` varchar(100) DEFAULT NULL COMMENT '保護者カナ',
  `member_tel` varchar(20) NOT NULL COMMENT '電話番号 (ハイフン含む)',
  `member_em_tel` varchar(20) DEFAULT NULL COMMENT '緊急連絡先',
  `member_post` varchar(8) DEFAULT NULL COMMENT '郵便番号 (ハイフン含む)',
  `member_address1` varchar(255) DEFAULT NULL COMMENT '住所１ (都道府県・市区町村・番地)',
  `member_address2` varchar(255) DEFAULT NULL COMMENT '住所２ (ビル・マンション名・部屋番号等)',
  `member_mail` varchar(255) DEFAULT NULL COMMENT 'メールアドレス',
  `member_birthday` date DEFAULT NULL COMMENT '生年月日',
  `member_sex` varchar(10) DEFAULT NULL COMMENT '性別 (例: ''男性'',''女性'' 等。あるいは区分値)',
  `member_join` date DEFAULT NULL COMMENT '入会日',
  `cancel_membership` date DEFAULT NULL COMMENT '退会日',
  `recess` date DEFAULT NULL COMMENT '休会開始日',
  `remarks` text DEFAULT NULL COMMENT '備考',
  `credit_name` varchar(100) DEFAULT NULL COMMENT 'クレジットカード名義 (半角英字)',
  `created_at` timestamp NULL DEFAULT current_timestamp() COMMENT '作成日時',
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp() COMMENT '更新日時'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='会員管理テーブル';

